export function useResetForm<TValues extends Record<string, unknown> = Record<string, unknown>>() {
  const form = injectWithSelf(FormContextKey);
  if (!form) {
    if (__DEV__) {
      warn('No vee-validate <Form /> or `useForm` was detected in the component tree');
    }
  }
  return function resetForm(state?: Partial<FormState<TValues>>, opts?: ResetFormOpts) {
    if (!form) {
      return;
    }
    return form.resetForm(state, opts);
  };
}

import type { GlobalTheme } from '../config-provider'

type ComponentKey = Exclude<keyof GlobalTheme, 'name'>
type ComponentThemes = Array<Exclude<GlobalTheme[ComponentKey], undefined>>

export function createTheme(
  name: string,
  componentThemes: ComponentThemes
): GlobalTheme
export function createTheme(componentThemes: ComponentThemes): GlobalTheme
export function createTheme(
  name: string | ComponentThemes,
  componentThemes?: ComponentThemes
): GlobalTheme {
  const nameIsString = typeof name === 'string'
  const theme: GlobalTheme = {
    name: nameIsString ? name : 'customized-theme'
  }
  if (nameIsString) {
    if (componentThemes) {
      for (const cTheme of componentThemes) {
        theme[cTheme.name] = cTheme as any
      }
    }
  }
  else {
    for (const cTheme of name) {
      theme[cTheme.name] = cTheme as any
    }
  }
  return theme
}

function checkRecursiveUpdates(seen: CountMap, fn: SchedulerJob) {
  const count = seen.get(fn) || 0
  if (count > RECURSION_LIMIT) {
    const instance = fn.i
    const componentName = instance && getComponentName(instance.type)
    handleError(
      `Maximum recursive updates exceeded${
        componentName ? ` in component <${componentName}>` : ``
      }. ` +
        `This means you have a reactive effect that is mutating its own ` +
        `dependencies and thus recursively triggering itself. Possible sources ` +
        `include component template, render function, updated hook or ` +
        `watcher source function.`,
      null,
      ErrorCodes.APP_ERROR_HANDLER,
    )
    return true
  }
  seen.set(fn, count + 1)
  return false
}

export function parseAnchor (anchor: Anchor, isRtl: boolean) {
  let [side, align] = anchor.split(' ') as [Tblock | Tinline | 'center', Tblock | Tinline | 'center' | undefined]
  if (!align) {
    align =
      includes(block, side) ? 'start'
      : includes(inline, side) ? 'top'
      : 'center'
  }

  return {
    side: toPhysical(side, isRtl),
    align: toPhysical(align, isRtl),
  } as ParsedAnchor
}

export function toPhysical (str: 'center' | Tblock | Tinline, isRtl: boolean) {
  if (str === 'start') return isRtl ? 'right' : 'left'
  if (str === 'end') return isRtl ? 'left' : 'right'
  return str
}

function ensureDirectiveApp () {
  if (directiveApp) return

  directives = ref([])

  directiveApp = createApp({
    name: 'VTooltipDirectiveApp',
    setup () {
      return {
        directives,
      }
    },
    render () {
      return this.directives.map((directive) => {
        return h(TooltipDirective, {
          ...directive.options,
          shown: directive.shown || directive.options.shown,
          key: directive.id,
        })
      })
    },
    devtools: {
      hide: true,
    },
  })

  const mountTarget = document.createElement('div')
  document.body.appendChild(mountTarget)
  directiveApp.mount(mountTarget)
}

formatDateString() {
  // Returns a date formatter function
  return createDateFormatter(this.calendarLocale, {
    // Ensure we have year, month, day shown for screen readers/ARIA
    // If users really want to leave one of these out, they can
    // pass `undefined` for the property value
    year: DATE_FORMAT_NUMERIC,
    month: DATE_FORMAT_2_DIGIT,
    day: DATE_FORMAT_2_DIGIT,
    // Merge in user supplied options
    ...this.dateFormatOptions,
    // Ensure hours/minutes/seconds are not shown
    // As we do not support the time portion (yet)
    hour: undefined,
    minute: undefined,
    second: undefined,
    // Ensure calendar is gregorian
    calendar: CALENDAR_GREGORY
  })
}

