const warnedMessages = new Set()

export function warnOnce(location: string, message: string): void {
  const mergedMessage = `[naive/${location}]: ${message}`
  if (warnedMessages.has(mergedMessage))
    return
  warnedMessages.add(mergedMessage)
  console.error(mergedMessage)
}

export function warn(location: string, message: string): void {
  console.error(`[naive/${location}]: ${message}`)
}

export function error(location: string, message: string, error: unknown): void {
  console.error(`[naive/${location}]: ${message}`, error)
}

export function throwError(location: string, message: string): never {
  throw new Error(`[naive/${location}]: ${message}`)
}

export function useInjectionElementCollection(
  injectionName: string | InjectionKey<unknown>,
  collectionKey: string,
  getElement: () => HTMLElement | null
): void {
  const injection = inject<Record<string, HTMLElement[]> | null>(
    injectionName,
    null
  )
  if (injection === null)
    return
  if (!(collectionKey in injection)) {
    injection[collectionKey] = []
  }
  onMounted(() => {
    const el = getElement()
    if (!el)
      return
    injection[collectionKey].push(el)
  })
  onBeforeUnmount(() => {
    const collectionArray = injection[collectionKey]
    const element = getElement()
    const index = collectionArray.findIndex(
      collectionElement => collectionElement === element
    )
    if (~index)
      collectionArray.splice(index, 1)
  })
}

export function propsFactory<
  PropsOptions extends ComponentObjectPropsOptions
> (props: PropsOptions, source: string) {
  return <Defaults extends PartialKeys<PropsOptions> = {}>(
    defaults?: Defaults
  ): AppendDefault<PropsOptions, Defaults> => {
    return Object.keys(props).reduce<any>((obj, prop) => {
      const isObjectDefinition = typeof props[prop] === 'object' && props[prop] != null && !Array.isArray(props[prop])
      const definition = isObjectDefinition ? props[prop] : { type: props[prop] }

      if (defaults && prop in defaults) {
        obj[prop] = {
          ...definition,
          default: defaults[prop],
        }
      } else {
        obj[prop] = definition
      }

      if (source && !obj[prop].source) {
        obj[prop].source = source
      }

      return obj
    }, {})
  }
}

export function useReveal (props: RevealProps) {
  const defaultDuration = 900
  const duration = toRef(() => typeof props.reveal === 'object'
    ? Math.max(0, Number(props.reveal.duration ?? defaultDuration))
    : defaultDuration
  )

  const state = shallowRef(props.reveal ? 'initial' : 'disabled')

  onMounted(async () => {
    if (props.reveal) {
      state.value = 'initial'
      await new Promise(resolve => requestAnimationFrame(resolve))
      state.value = 'pending'
      await new Promise(resolve => setTimeout(resolve, duration.value))
      state.value = 'done'
    }
  })

  return {
    duration,
    state,
  }
}

export function useFlyout(options: UseFlyoutOptions) {
  const focus = ref(false)

  if (inBrowser) {
    !active && activateFocusTracking()

    listeners++

    const unwatch = watch(focusedElement, (el) => {
      if (el === options.el.value || options.el.value?.contains(el!)) {
        focus.value = true
        options.onFocus?.()
      } else {
        focus.value = false
        options.onBlur?.()
      }
    })

    onUnmounted(() => {
      unwatch()

      listeners--

      if (!listeners) {
        deactivateFocusTracking()
      }
    })
  }

  return readonly(focus)
}

export function resolveQuery (
  query: ?string,
  extraQuery: Dictionary<string> = {},
  _parseQuery: ?Function
): Dictionary<string> {
  const parse = _parseQuery || parseQuery
  let parsedQuery
  try {
    parsedQuery = parse(query || '')
  } catch (e) {
    process.env.NODE_ENV !== 'production' && warn(false, e.message)
    parsedQuery = {}
  }
  for (const key in extraQuery) {
    const value = extraQuery[key]
    parsedQuery[key] = Array.isArray(value)
      ? value.map(castQueryParamValue)
      : castQueryParamValue(value)
  }
  return parsedQuery
}

export function bind (el, { value, modifiers }) {
  const options = getOptions(el, value, modifiers)
  if (!options.content || getDefaultConfig(options.theme || 'tooltip', 'disabled')) {
    destroyTooltip(el)
  } else {
    let directive
    if (el.$_popper) {
      directive = el.$_popper
      directive.options.value = options
    } else {
      directive = createTooltip(el, value, modifiers)
    }

    // Manual show
    if (typeof value.shown !== 'undefined' && value.shown !== el.$_popperOldShown) {
      el.$_popperOldShown = value.shown
      value.shown ? directive.show() : directive.hide()
    }
  }
}

updateSlides() {
  this.pause(true)
  // Get all slides as DOM elements
  this.slides = selectAll('.carousel-item', this.$refs.inner)
  const numSlides = this.slides.length
  // Keep slide number in range
  const index = mathMax(0, mathMin(mathFloor(this.index), numSlides - 1))
  this.slides.forEach((slide, idx) => {
    const n = idx + 1
    if (idx === index) {
      addClass(slide, 'active')
      setAttr(slide, 'aria-current', 'true')
    } else {
      removeClass(slide, 'active')
      setAttr(slide, 'aria-current', 'false')
    }
    setAttr(slide, 'aria-posinset', String(n))
    setAttr(slide, 'aria-setsize', String(numSlides))
  })
  // Set slide as active
  this.setSlide(index)
  this.start(this.isPaused)
}

resolve (
  to: RawLocation,
  current?: Route,
  append?: boolean
): {
  location: Location,
  route: Route,
  href: string,
  // for backwards compat
  normalizedTo: Location,
  resolved: Route
} {
  current = current || this.history.current
  const location = normalizeLocation(to, current, append, this)
  const route = this.match(location, current)
  const fullPath = route.redirectedFrom || route.fullPath
  const base = this.history.base
  const href = createHref(base, fullPath, this.mode)
  return {
    location,
    route,
    href,
    // for backwards compat
    normalizedTo: location,
    resolved: route
  }
}

