setInputFiles(files) {
  // Try an set the file input files array so that `required`
  // constraint works for dropped files (will fail in IE11 though)
  // To be used only when dropping files
  try {
    // Firefox < 62 workaround exploiting https://bugzilla.mozilla.org/show_bug.cgi?id=1422655
    const dataTransfer = new ClipboardEvent('').clipboardData || new DataTransfer()
    // Add flattened files to temp `dataTransfer` object to get a true `FileList` array
    flattenDeep(cloneDeep(files)).forEach(file => {
      // Make sure to remove the custom `$path` attribute
      delete file.$path
      dataTransfer.items.add(file)
    })
    this.$refs.input.files = dataTransfer.files
  } catch {}
}

function update(event?: StorageEventLike) {
  if (event && event.storageArea !== storage)
    return

  if (event && event.key == null) {
    data.value = rawInit
    return
  }

  if (event && event.key !== keyComputed.value) {
    return
  }

  pauseWatch()

  try {
    const serializedData = serializer.write(data.value)
    if (event === undefined || event?.newValue !== serializedData) {
      data.value = read(event)
    }
  }
  catch (e) {
    onError(e)
  }
  finally {
    // use nextTick to avoid infinite loop
    if (event)
      nextTick(resumeWatch)
    else
      resumeWatch()
  }
}

import { onActivated, onDeactivated } from 'vue'

export function useReactivated(callback: () => void): {
  isDeactivated: boolean
} {
  const isDeactivatedRef = { isDeactivated: false }
  let activateStateInitialized = false
  onActivated(() => {
    isDeactivatedRef.isDeactivated = false
    if (!activateStateInitialized) {
      activateStateInitialized = true
      return
    }
    callback()
  })
  onDeactivated(() => {
    isDeactivatedRef.isDeactivated = true
    if (!activateStateInitialized) {
      activateStateInitialized = true
    }
  })
  return isDeactivatedRef
}

onClickDay(day) {
  // Clicking on a date "button" to select it
  const { selectedDate, activeDate } = this
  const clickedDate = parseYMD(day.ymd)
  if (!this.disabled && !day.isDisabled && !this.dateDisabled(clickedDate)) {
    if (!this.readonly) {
      // If readonly mode, we don't set the selected date, just the active date
      // If the clicked date is equal to the already selected date, we don't update the model
      this.selectedYMD = formatYMD(
        datesEqual(clickedDate, selectedDate) ? selectedDate : clickedDate
      )
      this.emitSelected(clickedDate)
    }
    this.activeYMD = formatYMD(
      datesEqual(clickedDate, activeDate) ? activeDate : createDate(clickedDate)
    )
    // Ensure grid is focused
    this.focus()
  }
}

function generateArrowOuterCSS (theme, key) {
  return generateCSSForComponent(theme, key, 'arrow-outer', (styles, { merged, inherited }, lines) => {
    if (styles.arrow && styles.arrow.enabled !== inherited.arrow?.enabled) {
      if (merged.arrow?.enabled) {
        lines.push(`visibility: visible`)
      } else {
        lines.push(`visibility: hidden`)
      }
    }

    if (merged.arrow?.enabled) {
      // Arrow enabled
      if (styles.border?.enabled) {
        lines.push(`border-color: ${generateColorCSS(styles.border)}`)
      } else if (!merged.border?.enabled && styles.backgroundColor != null) {
        lines.push(`border-color: ${generateColorCSS(styles.backgroundColor)}`)
      }
    }
  })
}

render(h, { props, data, children }) {
  const { items } = props

  // Build child nodes from items, if given
  let childNodes = children
  if (isArray(items)) {
    let activeDefined = false
    childNodes = items.map((item, idx) => {
      if (!isObject(item)) {
        item = { text: toString(item) }
      }
      // Copy the value here so we can normalize it
      let { active } = item
      if (active) {
        activeDefined = true
      }
      // Auto-detect active by position in list
      if (!active && !activeDefined) {
        active = idx + 1 === items.length
      }

      return h(BBreadcrumbItem, { props: { ...item, active } })
    })
  }

  return h('ol', mergeData(data, { staticClass: 'breadcrumb' }), childNodes)
}
